import { test, expect } from '../../fixtures/cdp.fixture';
import { waitForAppReady } from '../../fixtures/helpers';

// ---------------------------------------------------------------------------
// Shared locator constants — corrected to match actual component data-testid
// ---------------------------------------------------------------------------
const ER_MENU_LABEL = /Enhanced Resource/i;
const OPEN_MENU = /Open/i;
const ER_IFRAME_SELECTOR = 'iframe[title*="Enhanced Resource"]';

/**
 * Helper: Open an Enhanced Resource via the menu and wait for it to render. Returns the
 * frameLocator for the ER web view iframe.
 */
async function openEnhancedResource(mainPage: import('@playwright/test').Page) {
  const menuTrigger = mainPage.getByRole('menuitem', { name: OPEN_MENU });
  await menuTrigger.click();
  const erMenuItem = mainPage.getByRole('menuitem', { name: ER_MENU_LABEL });
  await erMenuItem.click();
  // Wait for dock tab
  const tab = mainPage.locator('.dock-tab', { hasText: ER_MENU_LABEL });
  await expect(tab).toBeVisible({ timeout: 15_000 });
  // Return the iframe frame locator
  return mainPage.frameLocator(ER_IFRAME_SELECTOR);
}

