test.describe('Enhanced Resources Journey Tests — Cross-WP Data Flow', () => {
  // -----------------------------------------------------------------------
  // Journey 7: Open ER -> Toggle Research Terms -> Scripture highlight
  //            changes -> Linked words affected
  //   Spans: UI-PKG-004 (ERToolbar) -> UI-PKG-003 (ScripturePane)
  // -----------------------------------------------------------------------

  // @scenario BHV-404 (TS-094, TS-095, TS-096), BHV-403
  // NOTE: researchTermsOn defaults to true, so showeverylink is ALREADY present
  // when the ER opens. This test verifies: initial ON -> toggle OFF -> toggle ON.
  test('J-007: Toggle Research Terms highlight, verify scripture pane CSS classes update', async ({
    mainPage,
  }) => {
    await waitForAppReady(mainPage);

    // Step 1: Open ER (UI-PKG-001)
    const frame = await openEnhancedResource(mainPage);
    await expect(frame.locator('[data-testid="er-web-view"]')).toBeVisible({
      timeout: 15_000,
    });

    // Step 2: Locate toolbar with highlight toggles (UI-PKG-004)
    const toolbar = frame.locator('[data-testid="er-toolbar"]');
    await expect(toolbar).toBeVisible({ timeout: 10_000 });

    // Step 3: Verify Research Terms toggle button exists and is in ON state
    const researchTermsToggle = frame.locator('[data-testid="btn-research-terms"]');
    await expect(researchTermsToggle).toBeVisible();
    // Default state is ON (aria-pressed="true")
    await expect(researchTermsToggle).toHaveAttribute('aria-pressed', 'true', {
      timeout: 5_000,
    });

    // Step 4: Verify scripture content already has showeverylink class (default ON)
    const scriptureContent = frame.locator('[data-testid="scripture-content"]');
    await expect(scriptureContent).toBeVisible({ timeout: 10_000 });
    await expect(scriptureContent).toHaveClass(/showeverylink/, {
      timeout: 5_000,
    });

    // Step 5: Verify researchable-word elements exist in the scripture
    const researchableWords = scriptureContent.locator('.researchable-word');
    await expect(researchableWords.first()).toBeVisible({ timeout: 5_000 });

    // Step 6: Toggle OFF Research Terms (UI-PKG-004)
    await researchTermsToggle.click();

    // Step 7: Verify showeverylink class removed (UI-PKG-003)
    await expect(scriptureContent).not.toHaveClass(/showeverylink/, {
      timeout: 5_000,
    });

    // Step 8: Toggle back ON Research Terms
    await researchTermsToggle.click();

    // Step 9: Verify showeverylink class restored
    await expect(scriptureContent).toHaveClass(/showeverylink/, {
      timeout: 5_000,
    });

    // Evidence
    await mainPage.screenshot({
      path: 'e2e-tests/test-results/journey/JEVD-007-highlight-toggle-flow.png',
    });
  });

  // -----------------------------------------------------------------------
  // Journey 8: Open ER -> Select tracked project -> Found/Missing enabled
  //            -> Toggle highlights -> Scripture CSS changes
  //   Spans: UI-PKG-004 (ERToolbar) -> UI-PKG-003 (ScripturePane)
  //
  //   NOTE: This test requires available projects in the tracked project
  //   dropdown. With fallback data the dropdown may be empty, so the test
  //   conditionally proceeds only if projects are available.
  // -----------------------------------------------------------------------

  // @scenario BHV-404 (TS-089 through TS-096, TS-131, TS-132)
  test('J-008: Select tracked project, enable Found/Missing toggles, verify scripture highlights', async ({
    mainPage,
  }) => {
    await waitForAppReady(mainPage);

    // Step 1: Open ER (UI-PKG-001)
    const frame = await openEnhancedResource(mainPage);
    await expect(frame.locator('[data-testid="er-web-view"]')).toBeVisible({
      timeout: 15_000,
    });

    // Step 2: Locate tracked project dropdown in toolbar (UI-PKG-004)
    const trackedProjectDropdown = frame.locator('[data-testid="tracked-project-dropdown"]');
    await expect(trackedProjectDropdown).toBeVisible({ timeout: 10_000 });

    // Step 3: Verify Found/Missing buttons are initially disabled (no project tracked)
    // Actual testids: "btn-found" and "btn-missing"
    const foundToggle = frame.locator('[data-testid="btn-found"]');
    const missingToggle = frame.locator('[data-testid="btn-missing"]');
    await expect(foundToggle).toBeDisabled();
    await expect(missingToggle).toBeDisabled();

    // Step 4: Attempt to select a tracked project (UI-PKG-004)
    await trackedProjectDropdown.click();
    // Look for any project options (not "__none__")
    const projectOptions = frame.locator('[role="option"]').filter({ hasNotText: /No project/i });
    const projectOptionCount = await projectOptions.count();

    if (projectOptionCount > 0) {
      await projectOptions.first().click();

      // Step 5: Verify Found/Missing toggles become enabled (UI-PKG-004)
      await expect(foundToggle).toBeEnabled({ timeout: 10_000 });
      await expect(missingToggle).toBeEnabled({ timeout: 10_000 });

      // Step 6: Toggle Found highlight on (UI-PKG-004)
      await foundToggle.click();

      // Step 7: Verify scripture content adds showfound CSS class (UI-PKG-003)
      const scriptureContent = frame.locator('[data-testid="scripture-content"]');
      await expect(scriptureContent).toHaveClass(/showfound/, {
        timeout: 5_000,
      });

      // Step 8: Toggle Missing highlight on (UI-PKG-004)
      await missingToggle.click();

      // Step 9: Verify scripture content adds showmissing CSS class (UI-PKG-003)
      await expect(scriptureContent).toHaveClass(/showmissing/, {
        timeout: 5_000,
      });
    }
    // If no project options available, the test still passes (conditional flow)

    // Evidence
    await mainPage.screenshot({
      path: 'e2e-tests/test-results/journey/JEVD-008-tracked-project-flow.png',
    });
  });
});

